CREATE PROCEDURE assoc.sp_Finance_GetAssociationSummary @AssociationId INT, @TenantId INT AS BEGIN SET NOCOUNT ON; DECLARE @TotalOutstanding DECIMAL(18,2) = 0; SELECT @TotalOutstanding = ISNULL(SUM(CASE WHEN Type = 'Debit' THEN Amount ELSE -Amount END), 0) FROM assoc.Transactions WHERE TenantId = @TenantId AND AssociationId = @AssociationId AND Category != 'Credit Settlement' HAVING SUM(CASE WHEN Type = 'Debit' THEN Amount ELSE -Amount END) > 0; DECLARE @AdvanceCredits DECIMAL(18,2) = 0; DECLARE @UnitsWithCredit INT = 0; SELECT @AdvanceCredits = ISNULL(SUM(Amount), 0), @UnitsWithCredit = COUNT(DISTINCT AssetId) FROM assoc.Payments WHERE TenantId = @TenantId AND AssociationId = @AssociationId AND InvoiceId IS NULL AND Status IN ('Completed', 'Paid'); SELECT CAST(ISNULL(@TotalOutstanding, 0) AS DECIMAL(18,2)) as TotalOutstanding, CAST(ISNULL(@AdvanceCredits, 0) AS DECIMAL(18,2)) as TotalAdvanceCredits, ISNULL(@UnitsWithCredit, 0) as UnitsWithCredit; END